     1→"use client";
     2→
     3→import React, { useState, useEffect, Suspense } from "react";
     4→import useSWR from "swr";
     5→import { useRouter, useSearchParams } from "next/navigation";
     6→import { onboard as onboardApi, projects as projectsApi } from "@/lib/api/client";
     7→import type { OnboardScan, OnboardSelection, Project } from "@/lib/api/types";
     8→import { Loader2, Check, Search, ExternalLink, PackageSearch, ArrowRight } from "lucide-react";
     9→
    10→type Step = "input" | "scanning" | "results" | "applied";
    11→
    12→const ecosystemColors: Record<string, { bg: string; text: string; border: string }> = {
    13→  go: { bg: "#ecfeff", text: "#0e7490", border: "#a5f3fc" },
    14→  npm: { bg: "#fef2f2", text: "#b91c1c", border: "#fecaca" },
    15→  pypi: { bg: "#fefce8", text: "#a16207", border: "#fde68a" },
    16→  cargo: { bg: "#fff7ed", text: "#c2410c", border: "#fed7aa" },
    17→  rubygems: { bg: "#fdf2f8", text: "#be185d", border: "#fbcfe8" },
    18→  maven: { bg: "#eff6ff", text: "#1d4ed8", border: "#bfdbfe" },
    19→  gradle: { bg: "#eff6ff", text: "#1d4ed8", border: "#bfdbfe" },
    20→  docker: { bg: "#eff6ff", text: "#1d4ed8", border: "#bfdbfe" },
    21→  other: { bg: "#f3f3f1", text: "#6b7280", border: "#e8e8e5" },
    22→};
    23→
    24→export default function OnboardPage() {
    25→  return (
    26→    <Suspense>
    27→      <OnboardPageInner />
    28→    </Suspense>
    29→  );
    30→}
    31→
    32→function OnboardPageInner() {
    33→  const router = useRouter();
    34→  const searchParams = useSearchParams();
    35→  const [step, setStep] = useState<Step>("input");
    36→  const [repoUrl, setRepoUrl] = useState("");
    37→  const [scanId, setScanId] = useState<string | null>(null);
    38→  const [scan, setScan] = useState<OnboardScan | null>(null);
    39→  const [selections, setSelections] = useState<Record<number, boolean>>({});
    40→  const [projectAssignments, setProjectAssignments] = useState<Record<number, { mode: "new" | "existing"; projectId?: string; newName?: string }>>({});
    41→  const [applying, setApplying] = useState(false);
    42→  const [applyResult, setApplyResult] = useState<{ created_projects: Project[]; created_sources: any[]; skipped: string[] } | null>(null);
    43→  const [error, setError] = useState<string | null>(null);
    44→  const [autoStarted, setAutoStarted] = useState(false);
    45→  const [elapsed, setElapsed] = useState(0);
    46→
    47→  // Fetch existing projects for the dropdown
    48→  const { data: projectsResp } = useSWR("projects-all", () => projectsApi.list(1, 200));
    49→  const existingProjects = projectsResp?.data ?? [];
    50→
    51→  // Poll scan status
    52→  useEffect(() => {
    53→    if (step !== "scanning" || !scanId) return;
    54→    const interval = setInterval(async () => {
    55→      try {
    56→        const resp = await onboardApi.getScan(scanId);
    57→        setScan(resp.data);
    58→        if (resp.data.status === "completed") {
    59→          setStep("results");
    60→          const deps = resp.data.results ?? [];
    61→          const sel: Record<number, boolean> = {};
    62→          const assign: Record<number, { mode: "new" | "existing"; newName?: string }> = {};
    63→          deps.forEach((d, i) => {
    64→            sel[i] = true;
    65→            assign[i] = { mode: "new", newName: d.name.replace(/\//g, "-") };
    66→          });
    67→          setSelections(sel);
    68→          setProjectAssignments(assign);
    69→          clearInterval(interval);
    70→        } else if (resp.data.status === "failed") {
    71→          setError(resp.data.error || "Scan failed");
    72→          setStep("input");
    73→          clearInterval(interval);
    74→        }
    75→      } catch {
    76→        // Keep polling
    77→      }
    78→    }, 2000);
    79→    return () => clearInterval(interval);
    80→  }, [step, scanId]);
    81→
    82→  // Elapsed time counter during scanning
    83→  useEffect(() => {
    84→    if (step !== "scanning") { setElapsed(0); return; }
    85→    const start = Date.now();
    86→    const timer = setInterval(() => setElapsed(Math.floor((Date.now() - start) / 1000)), 1000);
    87→    return () => clearInterval(timer);
    88→  }, [step]);
    89→
    90→  // Auto-start scan from ?repo= query param
    91→  useEffect(() => {
    92→    const repo = searchParams.get("repo");
    93→    if (repo && !autoStarted) {
    94→      setAutoStarted(true);
    95→      setRepoUrl(repo);
    96→      beginScan(repo);
    97→    }
    98→  }, [searchParams, autoStarted]);
    99→
   100→  const beginScan = async (url: string) => {
   101→    setError(null);
   102→    try {
   103→      const resp = await onboardApi.scan(url);
   104→      const scanData = resp.data;
   105→      setScanId(scanData.id);
   106→      setScan(scanData);
   107→      // If scan is already completed (resuming a finished scan), go straight to results
   108→      if (scanData.status === "completed") {
   109→        const deps = scanData.results ?? [];
   110→        const sel: Record<number, boolean> = {};
   111→        const assign: Record<number, { mode: "new" | "existing"; newName?: string }> = {};
   112→        deps.forEach((d, i) => {
   113→          sel[i] = true;
   114→          assign[i] = { mode: "new", newName: d.name.replace(/\//g, "-") };
   115→        });
   116→        setSelections(sel);
   117→        setProjectAssignments(assign);
   118→        setStep("results");
   119→      } else if (scanData.status === "failed") {
   120→        setError(scanData.error || "Scan failed");
   121→        setStep("input");
   122→      } else {
   123→        setStep("scanning");
   124→      }
   125→    } catch (e: any) {
   126→      setError(e.message || "Failed to start scan");
   127→    }
   128→  };
   129→
   130→  const startScan = () => {
   131→    if (repoUrl.trim()) beginScan(repoUrl);
   132→  };
   133→
   134→  const applySelections = async () => {
   135→    if (!scan?.results || !scanId) return;
   136→    setApplying(true);
   137→    setError(null);
   138→
   139→    const sels: OnboardSelection[] = [];
   140→    scan.results.forEach((dep, i) => {
   141→      if (!selections[i]) return;
   142→      const assign = projectAssignments[i];
   143→      sels.push({
   144→        dep_name: dep.name,
   145→        upstream_repo: dep.upstream_repo,
   146→        provider: dep.provider,
   147→        project_id: assign?.mode === "existing" ? assign.projectId : undefined,
   148→        new_project_name: assign?.mode === "new" ? (assign.newName || dep.name.replace(/\//g, "-")) : undefined,
   149→      });
   150→    });
   151→
   152→    try {
   153→      const resp = await onboardApi.apply(scanId, sels);
   154→      setApplyResult(resp.data);
   155→      setStep("applied");
   156→    } catch (e: any) {
   157→      setError(e.message || "Failed to apply selections");
   158→    } finally {
   159→      setApplying(false);
   160→    }
   161→  };
   162→
   163→  const deps = scan?.results ?? [];
   164→  const selectedCount = Object.values(selections).filter(Boolean).length;
   165→
   166→  return (
   167→    <div className="flex flex-col gap-4 fade-in">
   168→      {/* Header */}
   169→      <div>
   170→        <h1
   171→          style={{
   172→            fontFamily: "var(--font-fraunces)",
   173→            fontSize: "24px",
   174→            fontWeight: 700,
   175→            color: "#111113",
   176→          }}
   177→        >
   178→          Quick Onboard
   179→        </h1>
   180→        <p
   181→          className="mt-1 text-[13px]"
   182→          style={{ color: "#6b7280", fontFamily: "var(--font-dm-sans)" }}
   183→        >
   184→          Scan a GitHub repository to detect dependencies and start tracking their releases.
   185→        </p>
   186→      </div>
   187→
   188→      {error && (
   189→        <div
   190→          className="rounded-md px-4 py-3 text-[13px]"
   191→          style={{
   192→            backgroundColor: "#fef2f2",
   193→            border: "1px solid #fecaca",
   194→            color: "#b91c1c",
   195→            fontFamily: "var(--font-dm-sans)",
   196→          }}
   197→        >
   198→          {error}
   199→        </div>
   200→      )}
   201→
   202→      {/* Step 1: Input */}
   203→      {step === "input" && (
   204→        <div
   205→          className="rounded-md px-6 py-8"
   206→          style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
   207→        >
   208→          <div className="max-w-xl">
   209→            <label
   210→              className="block text-[13px] font-medium mb-2"
   211→              style={{ color: "#374151", fontFamily: "var(--font-dm-sans)" }}
   212→            >
   213→              GitHub Repository URL
   214→            </label>
   215→            <div className="flex gap-2">
   216→              <input
   217→                type="text"
   218→                value={repoUrl}
   219→                onChange={(e) => setRepoUrl(e.target.value)}
   220→                placeholder="owner/repo or https://github.com/owner/repo"
   221→                className="flex-1 rounded-md border px-3 py-2 text-[13px] focus:outline-none focus:ring-2"
   222→                style={{
   223→                  borderColor: "#e8e8e5",
   224→                  color: "#111113",
   225→                  fontFamily: "'JetBrains Mono', monospace",
   226→                  backgroundColor: "#ffffff",
   227→                }}
   228→                onFocus={(e) => { e.currentTarget.style.borderColor = "#e8601a"; }}
   229→                onBlur={(e) => { e.currentTarget.style.borderColor = "#e8e8e5"; }}
   230→                onKeyDown={(e) => e.key === "Enter" && repoUrl.trim() && startScan()}
   231→              />
   232→              <button
   233→                onClick={startScan}
   234→                disabled={!repoUrl.trim()}
   235→                className="flex items-center gap-2 rounded-md px-4 py-2 text-[13px] font-medium text-white transition-opacity hover:opacity-90 disabled:opacity-40 disabled:cursor-not-allowed"
   236→                style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   237→              >
   238→                <Search className="h-4 w-4" />
   239→                Scan
   240→              </button>
   241→            </div>
   242→            <p className="mt-2 text-[12px]" style={{ color: "#9ca3af" }}>
   243→              We&apos;ll scan for go.mod, package.json, requirements.txt, Cargo.toml, and other dependency files.
   244→            </p>
   245→          </div>
   246→        </div>
   247→      )}
   248→
   249→      {/* Step 2: Scanning */}
   250→      {step === "scanning" && (
   251→        <div
   252→          className="flex flex-col items-center justify-center rounded-md py-16"
   253→          style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
   254→        >
   255→          <div
   256→            className="flex items-center justify-center rounded-full mb-4"
   257→            style={{ width: 48, height: 48, backgroundColor: "#fff7ed" }}
   258→          >
   259→            <Loader2 className="h-6 w-6 animate-spin" style={{ color: "#e8601a" }} />
   260→          </div>
   261→          <p
   262→            className="text-[14px] font-medium"
   263→            style={{ color: "#111113", fontFamily: "var(--font-dm-sans)" }}
   264→          >
   265→            {scan?.status === "processing"
   266→              ? "Analyzing dependency files..."
   267→              : "Waiting to start scan..."}
   268→          </p>
   269→          <div className="mt-3 flex flex-col items-center gap-2">
   270→            {/* Progress steps */}
   271→            <div className="flex items-center gap-6">
   272→              <ScanStep
   273→                label="Queued"
   274→                done={scan?.status === "processing"}
   275→                active={scan?.status === "pending"}
   276→              />
   277→              <StepConnector done={scan?.status === "processing"} />
   278→              <ScanStep
   279→                label="Fetching files"
   280→                done={false}
   281→                active={scan?.status === "processing"}
   282→              />
   283→              <StepConnector done={false} />
   284→              <ScanStep
   285→                label="Extracting deps"
   286→                done={false}
   287→                active={false}
   288→              />
   289→            </div>
   290→            <p className="mt-2 text-[12px]" style={{ color: "#9ca3af" }}>
   291→              {elapsed > 0 && `${elapsed}s elapsed · `}
   292→              {scan?.repo_url && (
   293→                <span style={{ fontFamily: "'JetBrains Mono', monospace" }}>{scan.repo_url}</span>
   294→              )}
   295→            </p>
   296→          </div>
   297→        </div>
   298→      )}
   299→
   300→      {/* Step 3: Results — empty */}
   301→      {step === "results" && deps.length === 0 && (
   302→        <div
   303→          className="flex flex-col items-center justify-center rounded-md py-16"
   304→          style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
   305→        >
   306→          <PackageSearch className="h-8 w-8 mb-3" style={{ color: "#c4c4c0" }} />
   307→          <p
   308→            className="text-[14px]"
   309→            style={{ color: "#6b7280", fontFamily: "var(--font-dm-sans)" }}
   310→          >
   311→            No dependencies detected in this repository.
   312→          </p>
   313→          <button
   314→            onClick={() => { setStep("input"); setRepoUrl(""); }}
   315→            className="mt-4 text-[13px] font-medium hover:underline"
   316→            style={{ color: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   317→          >
   318→            Try another repository
   319→          </button>
   320→        </div>
   321→      )}
   322→
   323→      {/* Step 3: Results — with deps */}
   324→      {step === "results" && deps.length > 0 && (
   325→        <>
   326→          <div className="flex items-center justify-between">
   327→            <p className="text-[13px]" style={{ color: "#6b7280", fontFamily: "var(--font-dm-sans)" }}>
   328→              Found <span style={{ color: "#111113", fontWeight: 600 }}>{deps.length}</span> dependencies.
   329→              {" "}Selected: <span style={{ color: "#111113", fontWeight: 600 }}>{selectedCount}</span>
   330→            </p>
   331→            <button
   332→              onClick={applySelections}
   333→              disabled={selectedCount === 0 || applying}
   334→              className="flex items-center gap-2 rounded-md px-4 py-2 text-[13px] font-medium text-white transition-opacity hover:opacity-90 disabled:opacity-40"
   335→              style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   336→            >
   337→              {applying ? <Loader2 className="h-4 w-4 animate-spin" /> : <PackageSearch className="h-4 w-4" />}
   338→              Track Selected ({selectedCount})
   339→            </button>
   340→          </div>
   341→
   342→          <div
   343→            className="overflow-hidden rounded-md"
   344→            style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
   345→          >
   346→            <table className="w-full text-[13px]" style={{ fontFamily: "var(--font-dm-sans)" }}>
   347→              <thead>
   348→                <tr style={{ borderBottom: "1px solid #e8e8e5", backgroundColor: "#fafaf9" }}>
   349→                  <th className="w-10 px-3 py-2.5">
   350→                    <input
   351→                      type="checkbox"
   352→                      checked={selectedCount === deps.length}
   353→                      onChange={(e) => {
   354→                        const val = e.target.checked;
   355→                        const s: Record<number, boolean> = {};
   356→                        deps.forEach((_, i) => { s[i] = val; });
   357→                        setSelections(s);
   358→                      }}
   359→                      className="rounded"
   360→                      style={{ accentColor: "#e8601a" }}
   361→                    />
   362→                  </th>
   363→                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
   364→                    Dependency
   365→                  </th>
   366→                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
   367→                    Version
   368→                  </th>
   369→                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
   370→                    Ecosystem
   371→                  </th>
   372→                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
   373→                    Source
   374→                  </th>
   375→                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
   376→                    Project
   377→                  </th>
   378→                </tr>
   379→              </thead>
   380→              <tbody>
   381→                {deps.map((dep, i) => {
   382→                  const eco = ecosystemColors[dep.ecosystem] || ecosystemColors.other;
   383→                  return (
   384→                    <tr
   385→                      key={i}
   386→                      className="transition-colors hover:bg-[#fafaf9]"
   387→                      style={{
   388→                        borderBottom: i < deps.length - 1 ? "1px solid #e8e8e5" : undefined,
   389→                        opacity: selections[i] ? 1 : 0.5,
   390→                      }}
   391→                    >
   392→                      <td className="px-3 py-2.5">
   393→                        <input
   394→                          type="checkbox"
   395→                          checked={!!selections[i]}
   396→                          onChange={(e) => setSelections({ ...selections, [i]: e.target.checked })}
   397→                          className="rounded"
   398→                          style={{ accentColor: "#e8601a" }}
   399→                        />
   400→                      </td>
   401→                      <td className="px-3 py-2.5">
   402→                        <span
   403→                          className="text-[12px]"
   404→                          style={{ fontFamily: "'JetBrains Mono', monospace", color: "#111113" }}
   405→                        >
   406→                          {dep.name}
   407→                        </span>
   408→                      </td>
   409→                      <td className="px-3 py-2.5">
   410→                        <span
   411→                          className="inline-flex items-center rounded px-1.5 py-0.5 text-[11px]"
   412→                          style={{
   413→                            backgroundColor: "#f3f3f1",
   414→                            fontFamily: "'JetBrains Mono', monospace",
   415→                            color: "#374151",
   416→                          }}
   417→                        >
   418→                          {dep.version}
   419→                        </span>
   420→                      </td>
   421→                      <td className="px-3 py-2.5">
   422→                        <span
   423→                          className="inline-flex items-center rounded-full px-2 py-0.5 text-[11px] font-medium"
   424→                          style={{
   425→                            backgroundColor: eco.bg,
   426→                            color: eco.text,
   427→                            border: `1px solid ${eco.border}`,
   428→                          }}
   429→                        >
   430→                          {dep.ecosystem}
   431→                        </span>
   432→                      </td>
   433→                      <td className="px-3 py-2.5">
   434→                        <span className="text-[12px]" style={{ color: "#6b7280", fontFamily: "'JetBrains Mono', monospace" }}>
   435→                          {dep.upstream_repo}
   436→                        </span>
   437→                      </td>
   438→                      <td className="px-3 py-2.5">
   439→                        <select
   440→                          value={projectAssignments[i]?.mode === "existing" ? projectAssignments[i]?.projectId : "__new__"}
   441→                          onChange={(e) => {
   442→                            const val = e.target.value;
   443→                            if (val === "__new__") {
   444→                              setProjectAssignments({
   445→                                ...projectAssignments,
   446→                                [i]: { mode: "new", newName: dep.name.replace(/\//g, "-") },
   447→                              });
   448→                            } else {
   449→                              setProjectAssignments({
   450→                                ...projectAssignments,
   451→                                [i]: { mode: "existing", projectId: val },
   452→                              });
   453→                            }
   454→                          }}
   455→                          className="rounded-md border px-2 py-1 text-[12px] bg-white"
   456→                          style={{
   457→                            borderColor: "#e8e8e5",
   458→                            color: "#374151",
   459→                            fontFamily: "var(--font-dm-sans)",
   460→                          }}
   461→                        >
   462→                          <option value="__new__">Create new project</option>
   463→                          {existingProjects.map((p) => (
   464→                            <option key={p.id} value={p.id}>{p.name}</option>
   465→                          ))}
   466→                        </select>
   467→                      </td>
   468→                    </tr>
   469→                  );
   470→                })}
   471→              </tbody>
   472→            </table>
   473→          </div>
   474→        </>
   475→      )}
   476→
   477→      {/* Step 4: Applied */}
   478→      {step === "applied" && applyResult && (
   479→        <>
   480→          <div
   481→            className="rounded-md px-4 py-3 text-[13px]"
   482→            style={{
   483→              backgroundColor: "#f0fdf4",
   484→              border: "1px solid #bbf7d0",
   485→              color: "#15803d",
   486→              fontFamily: "var(--font-dm-sans)",
   487→            }}
   488→          >
   489→            <div className="flex items-center gap-2">
   490→              <Check className="h-4 w-4" />
   491→              Successfully created {applyResult.created_sources.length} source{applyResult.created_sources.length !== 1 ? "s" : ""}
   492→              {applyResult.created_projects.length > 0 && ` and ${applyResult.created_projects.length} project${applyResult.created_projects.length !== 1 ? "s" : ""}`}.
   493→            </div>
   494→          </div>
   495→
   496→          {applyResult.skipped.length > 0 && (
   497→            <div
   498→              className="rounded-md px-4 py-3 text-[13px]"
   499→              style={{
   500→                backgroundColor: "#fefce8",
   501→                border: "1px solid #fde68a",
   502→                color: "#a16207",
   503→                fontFamily: "var(--font-dm-sans)",
   504→              }}
   505→            >
   506→              <p className="font-medium mb-1">Skipped ({applyResult.skipped.length}):</p>
   507→              <ul className="list-disc pl-5 text-[12px]">
   508→                {applyResult.skipped.map((s, i) => <li key={i}>{s}</li>)}
   509→              </ul>
   510→            </div>
   511→          )}
   512→
   513→          <div className="flex gap-3">
   514→            <button
   515→              onClick={() => router.push("/projects")}
   516→              className="flex items-center gap-2 rounded-md px-4 py-2 text-[13px] font-medium text-white transition-opacity hover:opacity-90"
   517→              style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   518→            >
   519→              View Projects
   520→              <ArrowRight className="h-3.5 w-3.5" />
   521→            </button>
   522→            <button
   523→              onClick={() => { setStep("input"); setRepoUrl(""); setScanId(null); setScan(null); setApplyResult(null); }}
   524→              className="rounded-md border px-4 py-2 text-[13px] transition-colors hover:bg-[#f3f3f1]"
   525→              style={{
