"use client";

import React, { useState, useEffect, Suspense } from "react";
import useSWR from "swr";
import { useRouter, useSearchParams } from "next/navigation";
import { onboard as onboardApi, projects as projectsApi } from "@/lib/api/client";
import type { OnboardScan, OnboardSelection, Project } from "@/lib/api/types";
import { Loader2, Check, Search, ExternalLink, PackageSearch, ArrowRight } from "lucide-react";

type Step = "input" | "scanning" | "results" | "applied";

const ecosystemColors: Record<string, { bg: string; text: string; border: string }> = {
  go: { bg: "#ecfeff", text: "#0e7490", border: "#a5f3fc" },
  npm: { bg: "#fef2f2", text: "#b91c1c", border: "#fecaca" },
  pypi: { bg: "#fefce8", text: "#a16207", border: "#fde68a" },
  cargo: { bg: "#fff7ed", text: "#c2410c", border: "#fed7aa" },
  rubygems: { bg: "#fdf2f8", text: "#be185d", border: "#fbcfe8" },
  maven: { bg: "#eff6ff", text: "#1d4ed8", border: "#bfdbfe" },
  gradle: { bg: "#eff6ff", text: "#1d4ed8", border: "#bfdbfe" },
  docker: { bg: "#eff6ff", text: "#1d4ed8", border: "#bfdbfe" },
  other: { bg: "#f3f3f1", text: "#6b7280", border: "#e8e8e5" },
};

export default function OnboardPage() {
  return (
    <Suspense>
      <OnboardPageInner />
    </Suspense>
  );
}

function OnboardPageInner() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const [step, setStep] = useState<Step>("input");
  const [repoUrl, setRepoUrl] = useState("");
  const [scanId, setScanId] = useState<string | null>(null);
  const [scan, setScan] = useState<OnboardScan | null>(null);
  const [selections, setSelections] = useState<Record<number, boolean>>({});
  const [projectAssignments, setProjectAssignments] = useState<Record<number, { mode: "new" | "existing"; projectId?: string; newName?: string }>>({});
  const [applying, setApplying] = useState(false);
  const [applyResult, setApplyResult] = useState<{ created_projects: Project[]; created_sources: any[]; skipped: string[] } | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [autoStarted, setAutoStarted] = useState(false);
  const [elapsed, setElapsed] = useState(0);

  // Fetch existing projects for the dropdown
  const { data: projectsResp } = useSWR("projects-all", () => projectsApi.list(1, 200));
  const existingProjects = projectsResp?.data ?? [];

  // Poll scan status
  useEffect(() => {
    if (step !== "scanning" || !scanId) return;
    const interval = setInterval(async () => {
      try {
        const resp = await onboardApi.getScan(scanId);
        setScan(resp.data);
        if (resp.data.status === "completed") {
          setStep("results");
          const deps = resp.data.results ?? [];
          const sel: Record<number, boolean> = {};
          const assign: Record<number, { mode: "new" | "existing"; newName?: string }> = {};
          deps.forEach((d, i) => {
            sel[i] = true;
            assign[i] = { mode: "new", newName: d.name.replace(/\//g, "-") };
          });
          setSelections(sel);
          setProjectAssignments(assign);
          clearInterval(interval);
        } else if (resp.data.status === "failed") {
          setError(resp.data.error || "Scan failed");
          setStep("input");
          clearInterval(interval);
        }
      } catch {
        // Keep polling
      }
    }, 2000);
    return () => clearInterval(interval);
  }, [step, scanId]);

  // Elapsed time counter during scanning
  useEffect(() => {
    if (step !== "scanning") { setElapsed(0); return; }
    const start = Date.now();
    const timer = setInterval(() => setElapsed(Math.floor((Date.now() - start) / 1000)), 1000);
    return () => clearInterval(timer);
  }, [step]);

  // Auto-start scan from ?repo= query param
  useEffect(() => {
    const repo = searchParams.get("repo");
    if (repo && !autoStarted) {
      setAutoStarted(true);
      setRepoUrl(repo);
      beginScan(repo);
    }
  }, [searchParams, autoStarted]);

  const beginScan = async (url: string) => {
    setError(null);
    try {
      const resp = await onboardApi.scan(url);
      const scanData = resp.data;
      setScanId(scanData.id);
      setScan(scanData);
      // If scan is already completed (resuming a finished scan), go straight to results
      if (scanData.status === "completed") {
        const deps = scanData.results ?? [];
        const sel: Record<number, boolean> = {};
        const assign: Record<number, { mode: "new" | "existing"; newName?: string }> = {};
        deps.forEach((d, i) => {
          sel[i] = true;
          assign[i] = { mode: "new", newName: d.name.replace(/\//g, "-") };
        });
        setSelections(sel);
        setProjectAssignments(assign);
        setStep("results");
      } else if (scanData.status === "failed") {
        setError(scanData.error || "Scan failed");
        setStep("input");
      } else {
        setStep("scanning");
      }
    } catch (e: any) {
      setError(e.message || "Failed to start scan");
    }
  };

  const startScan = () => {
    if (repoUrl.trim()) beginScan(repoUrl);
  };

  const applySelections = async () => {
    if (!scan?.results || !scanId) return;
    setApplying(true);
    setError(null);

    const sels: OnboardSelection[] = [];
    scan.results.forEach((dep, i) => {
      if (!selections[i]) return;
      const assign = projectAssignments[i];
      sels.push({
        dep_name: dep.name,
        upstream_repo: dep.upstream_repo,
        provider: dep.provider,
        project_id: assign?.mode === "existing" ? assign.projectId : undefined,
        new_project_name: assign?.mode === "new" ? (assign.newName || dep.name.replace(/\//g, "-")) : undefined,
      });
    });

    try {
      const resp = await onboardApi.apply(scanId, sels);
      setApplyResult(resp.data);
      setStep("applied");
    } catch (e: any) {
      setError(e.message || "Failed to apply selections");
    } finally {
      setApplying(false);
    }
  };

  const deps = scan?.results ?? [];
  const selectedCount = Object.values(selections).filter(Boolean).length;

  return (
    <div className="flex flex-col gap-4 fade-in">
      {/* Header */}
      <div>
        <h1
          style={{
            fontFamily: "var(--font-fraunces)",
            fontSize: "24px",
            fontWeight: 700,
            color: "#111113",
          }}
        >
          Quick Onboard
        </h1>
        <p
          className="mt-1 text-[13px]"
          style={{ color: "#6b7280", fontFamily: "var(--font-dm-sans)" }}
        >
          Scan a GitHub repository to detect dependencies and start tracking their releases.
        </p>
      </div>

      {error && (
        <div
          className="rounded-md px-4 py-3 text-[13px]"
          style={{
            backgroundColor: "#fef2f2",
            border: "1px solid #fecaca",
            color: "#b91c1c",
            fontFamily: "var(--font-dm-sans)",
          }}
        >
          {error}
        </div>
      )}

      {/* Step 1: Input */}
      {step === "input" && (
        <div
          className="rounded-md px-6 py-8"
          style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
        >
          <div className="max-w-xl">
            <label
              className="block text-[13px] font-medium mb-2"
              style={{ color: "#374151", fontFamily: "var(--font-dm-sans)" }}
            >
              GitHub Repository URL
            </label>
            <div className="flex gap-2">
              <input
                type="text"
                value={repoUrl}
                onChange={(e) => setRepoUrl(e.target.value)}
                placeholder="owner/repo or https://github.com/owner/repo"
                className="flex-1 rounded-md border px-3 py-2 text-[13px] focus:outline-none focus:ring-2"
                style={{
                  borderColor: "#e8e8e5",
                  color: "#111113",
                  fontFamily: "'JetBrains Mono', monospace",
                  backgroundColor: "#ffffff",
                }}
                onFocus={(e) => { e.currentTarget.style.borderColor = "#e8601a"; }}
                onBlur={(e) => { e.currentTarget.style.borderColor = "#e8e8e5"; }}
                onKeyDown={(e) => e.key === "Enter" && repoUrl.trim() && startScan()}
              />
              <button
                onClick={startScan}
                disabled={!repoUrl.trim()}
                className="flex items-center gap-2 rounded-md px-4 py-2 text-[13px] font-medium text-white transition-opacity hover:opacity-90 disabled:opacity-40 disabled:cursor-not-allowed"
                style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
              >
                <Search className="h-4 w-4" />
                Scan
              </button>
            </div>
            <p className="mt-2 text-[12px]" style={{ color: "#9ca3af" }}>
              We&apos;ll scan for go.mod, package.json, requirements.txt, Cargo.toml, and other dependency files.
            </p>
          </div>
        </div>
      )}

      {/* Step 2: Scanning */}
      {step === "scanning" && (
        <div
          className="flex flex-col items-center justify-center rounded-md py-16"
          style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
        >
          <div
            className="flex items-center justify-center rounded-full mb-4"
            style={{ width: 48, height: 48, backgroundColor: "#fff7ed" }}
          >
            <Loader2 className="h-6 w-6 animate-spin" style={{ color: "#e8601a" }} />
          </div>
          <p
            className="text-[14px] font-medium"
            style={{ color: "#111113", fontFamily: "var(--font-dm-sans)" }}
          >
            {scan?.status === "processing"
              ? "Analyzing dependency files..."
              : "Waiting to start scan..."}
          </p>
          <div className="mt-3 flex flex-col items-center gap-2">
            {/* Progress steps */}
            <div className="flex items-center gap-6">
              <ScanStep
                label="Queued"
                done={scan?.status === "processing"}
                active={scan?.status === "pending"}
              />
              <StepConnector done={scan?.status === "processing"} />
              <ScanStep
                label="Fetching files"
                done={false}
                active={scan?.status === "processing"}
              />
              <StepConnector done={false} />
              <ScanStep
                label="Extracting deps"
                done={false}
                active={false}
              />
            </div>
            <p className="mt-2 text-[12px]" style={{ color: "#9ca3af" }}>
              {elapsed > 0 && `${elapsed}s elapsed · `}
              {scan?.repo_url && (
                <span style={{ fontFamily: "'JetBrains Mono', monospace" }}>{scan.repo_url}</span>
              )}
            </p>
          </div>
        </div>
      )}

      {/* Step 3: Results — empty */}
      {step === "results" && deps.length === 0 && (
        <div
          className="flex flex-col items-center justify-center rounded-md py-16"
          style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
        >
          <PackageSearch className="h-8 w-8 mb-3" style={{ color: "#c4c4c0" }} />
          <p
            className="text-[14px]"
            style={{ color: "#6b7280", fontFamily: "var(--font-dm-sans)" }}
          >
            No dependencies detected in this repository.
          </p>
          <button
            onClick={() => { setStep("input"); setRepoUrl(""); }}
            className="mt-4 text-[13px] font-medium hover:underline"
            style={{ color: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
          >
            Try another repository
          </button>
        </div>
      )}

      {/* Step 3: Results — with deps */}
      {step === "results" && deps.length > 0 && (
        <>
          <div className="flex items-center justify-between">
            <p className="text-[13px]" style={{ color: "#6b7280", fontFamily: "var(--font-dm-sans)" }}>
              Found <span style={{ color: "#111113", fontWeight: 600 }}>{deps.length}</span> dependencies.
              {" "}Selected: <span style={{ color: "#111113", fontWeight: 600 }}>{selectedCount}</span>
            </p>
            <button
              onClick={applySelections}
              disabled={selectedCount === 0 || applying}
              className="flex items-center gap-2 rounded-md px-4 py-2 text-[13px] font-medium text-white transition-opacity hover:opacity-90 disabled:opacity-40"
              style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
            >
              {applying ? <Loader2 className="h-4 w-4 animate-spin" /> : <PackageSearch className="h-4 w-4" />}
              Track Selected ({selectedCount})
            </button>
          </div>

          <div
            className="overflow-hidden rounded-md"
            style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
          >
            <table className="w-full text-[13px]" style={{ fontFamily: "var(--font-dm-sans)" }}>
              <thead>
                <tr style={{ borderBottom: "1px solid #e8e8e5", backgroundColor: "#fafaf9" }}>
                  <th className="w-10 px-3 py-2.5">
                    <input
                      type="checkbox"
                      checked={selectedCount === deps.length}
                      onChange={(e) => {
                        const val = e.target.checked;
                        const s: Record<number, boolean> = {};
                        deps.forEach((_, i) => { s[i] = val; });
                        setSelections(s);
                      }}
                      className="rounded"
                      style={{ accentColor: "#e8601a" }}
                    />
                  </th>
                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
                    Dependency
                  </th>
                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
                    Version
                  </th>
                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
                    Ecosystem
                  </th>
                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
                    Source
                  </th>
                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
                    Project
                  </th>
                </tr>
              </thead>
              <tbody>
                {deps.map((dep, i) => {
                  const eco = ecosystemColors[dep.ecosystem] || ecosystemColors.other;
                  return (
                    <tr
                      key={i}
                      className="transition-colors hover:bg-[#fafaf9]"
                      style={{
                        borderBottom: i < deps.length - 1 ? "1px solid #e8e8e5" : undefined,
                        opacity: selections[i] ? 1 : 0.5,
                      }}
                    >
                      <td className="px-3 py-2.5">
                        <input
                          type="checkbox"
                          checked={!!selections[i]}
                          onChange={(e) => setSelections({ ...selections, [i]: e.target.checked })}
                          className="rounded"
                          style={{ accentColor: "#e8601a" }}
                        />
                      </td>
                      <td className="px-3 py-2.5">
                        <span
                          className="text-[12px]"
                          style={{ fontFamily: "'JetBrains Mono', monospace", color: "#111113" }}
                        >
                          {dep.name}
                        </span>
                      </td>
                      <td className="px-3 py-2.5">
                        <span
                          className="inline-flex items-center rounded px-1.5 py-0.5 text-[11px]"
                          style={{
                            backgroundColor: "#f3f3f1",
                            fontFamily: "'JetBrains Mono', monospace",
                            color: "#374151",
                          }}
                        >
                          {dep.version}
                        </span>
                      </td>
                      <td className="px-3 py-2.5">
                        <span
                          className="inline-flex items-center rounded-full px-2 py-0.5 text-[11px] font-medium"
                          style={{
                            backgroundColor: eco.bg,
                            color: eco.text,
                            border: `1px solid ${eco.border}`,
                          }}
                        >
                          {dep.ecosystem}
                        </span>
                      </td>
                      <td className="px-3 py-2.5">
                        <span className="text-[12px]" style={{ color: "#6b7280", fontFamily: "'JetBrains Mono', monospace" }}>
                          {dep.upstream_repo}
                        </span>
                      </td>
                      <td className="px-3 py-2.5">
                        <select
                          value={projectAssignments[i]?.mode === "existing" ? projectAssignments[i]?.projectId : "__new__"}
                          onChange={(e) => {
                            const val = e.target.value;
                            if (val === "__new__") {
                              setProjectAssignments({
                                ...projectAssignments,
                                [i]: { mode: "new", newName: dep.name.replace(/\//g, "-") },
                              });
                            } else {
                              setProjectAssignments({
                                ...projectAssignments,
                                [i]: { mode: "existing", projectId: val },
                              });
                            }
                          }}
                          className="rounded-md border px-2 py-1 text-[12px] bg-white"
                          style={{
                            borderColor: "#e8e8e5",
                            color: "#374151",
                            fontFamily: "var(--font-dm-sans)",
                          }}
                        >
                          <option value="__new__">Create new project</option>
                          {existingProjects.map((p) => (
                            <option key={p.id} value={p.id}>{p.name}</option>
                          ))}
                        </select>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </>
      )}

      {/* Step 4: Applied */}
      {step === "applied" && applyResult && (
        <>
          <div
            className="rounded-md px-4 py-3 text-[13px]"
            style={{
              backgroundColor: "#f0fdf4",
              border: "1px solid #bbf7d0",
              color: "#15803d",
              fontFamily: "var(--font-dm-sans)",
            }}
          >
            <div className="flex items-center gap-2">
              <Check className="h-4 w-4" />
              Successfully created {applyResult.created_sources.length} source{applyResult.created_sources.length !== 1 ? "s" : ""}
              {applyResult.created_projects.length > 0 && ` and ${applyResult.created_projects.length} project${applyResult.created_projects.length !== 1 ? "s" : ""}`}.
            </div>
          </div>

          {applyResult.skipped.length > 0 && (
            <div
              className="rounded-md px-4 py-3 text-[13px]"
              style={{
                backgroundColor: "#fefce8",
                border: "1px solid #fde68a",
                color: "#a16207",
                fontFamily: "var(--font-dm-sans)",
              }}
            >
              <p className="font-medium mb-1">Skipped ({applyResult.skipped.length}):</p>
              <ul className="list-disc pl-5 text-[12px]">
                {applyResult.skipped.map((s, i) => <li key={i}>{s}</li>)}
              </ul>
            </div>
          )}

          <div className="flex gap-3">
            <button
              onClick={() => router.push("/projects")}
              className="flex items-center gap-2 rounded-md px-4 py-2 text-[13px] font-medium text-white transition-opacity hover:opacity-90"
              style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
            >
              View Projects
              <ArrowRight className="h-3.5 w-3.5" />
            </button>
            <button
              onClick={() => { setStep("input"); setRepoUrl(""); setScanId(null); setScan(null); setApplyResult(null); }}
              className="rounded-md border px-4 py-2 text-[13px] transition-colors hover:bg-[#f3f3f1]"
              style={{
                borderColor: "#e8e8e5",
                color: "#374151",
                fontFamily: "var(--font-dm-sans)",
              }}
            >
              Scan Another Repo
            </button>
          </div>
        </>
      )}
    </div>
  );
}

/* --- Progress step components --- */

function ScanStep({ label, done, active }: { label: string; done: boolean; active: boolean }) {
  return (
    <div className="flex items-center gap-1.5">
      <div
        className="flex items-center justify-center rounded-full"
        style={{
          width: 18,
          height: 18,
          backgroundColor: done ? "#f0fdf4" : active ? "#fff7ed" : "#f3f3f1",
          border: `1.5px solid ${done ? "#16a34a" : active ? "#e8601a" : "#e8e8e5"}`,
        }}
      >
        {done ? (
          <Check className="h-3 w-3" style={{ color: "#16a34a" }} />
        ) : active ? (
          <Loader2 className="h-3 w-3 animate-spin" style={{ color: "#e8601a" }} />
        ) : (
          <div className="h-1.5 w-1.5 rounded-full" style={{ backgroundColor: "#d1d5db" }} />
        )}
      </div>
      <span
        className="text-[12px]"
        style={{
          color: done ? "#16a34a" : active ? "#111113" : "#9ca3af",
          fontFamily: "var(--font-dm-sans)",
          fontWeight: active ? 500 : 400,
        }}
      >
        {label}
      </span>
    </div>
  );
}

function StepConnector({ done }: { done: boolean }) {
  return (
    <div
      className="h-px"
      style={{
        width: 24,
        backgroundColor: done ? "#16a34a" : "#e8e8e5",
      }}
    />
  );
}

"use client";

import React, { useState, useEffect, Suspense } from "react";
import useSWR from "swr";
import { useRouter, useSearchParams } from "next/navigation";
import { onboard as onboardApi, projects as projectsApi } from "@/lib/api/client";
import type { OnboardScan, OnboardSelection, Project } from "@/lib/api/types";
import { Loader2, Check, Search, PackageSearch, ArrowRight } from "lucide-react";

type Step = "input" | "scanning" | "results" | "applied";

const ecosystemColors: Record<string, { bg: string; text: string; border: string }> = {
  go: { bg: "#ecfeff", text: "#0e7490", border: "#a5f3fc" },
  npm: { bg: "#fef2f2", text: "#b91c1c", border: "#fecaca" },
  pypi: { bg: "#fefce8", text: "#a16207", border: "#fde68a" },
  cargo: { bg: "#fff7ed", text: "#c2410c", border: "#fed7aa" },
  rubygems: { bg: "#fdf2f8", text: "#be185d", border: "#fbcfe8" },
  maven: { bg: "#eff6ff", text: "#1d4ed8", border: "#bfdbfe" },
  gradle: { bg: "#eff6ff", text: "#1d4ed8", border: "#bfdbfe" },
  docker: { bg: "#eff6ff", text: "#1d4ed8", border: "#bfdbfe" },
  other: { bg: "#f3f3f1", text: "#6b7280", border: "#e8e8e5" },
};

export default function OnboardPage() {
  return (
    <Suspense>
      <OnboardPageInner />
    </Suspense>
  );
}

function OnboardPageInner() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const [step, setStep] = useState<Step>("input");
  const [repoUrl, setRepoUrl] = useState("");
  const [scanId, setScanId] = useState<string | null>(null);
  const [scan, setScan] = useState<OnboardScan | null>(null);
  const [selections, setSelections] = useState<Record<number, boolean>>({});
  const [projectAssignments, setProjectAssignments] = useState<Record<number, { mode: "new" | "existing"; projectId?: string; newName?: string }>>({});
  const [applying, setApplying] = useState(false);
  const [applyResult, setApplyResult] = useState<{ created_projects: Project[]; created_sources: any[]; skipped: string[] } | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [autoStarted, setAutoStarted] = useState(false);
  const [elapsed, setElapsed] = useState(0);

  // Fetch existing projects for the dropdown
  const { data: projectsResp } = useSWR("projects-all", () => projectsApi.list(1, 200));
  const existingProjects = projectsResp?.data ?? [];

  // Poll scan status
  useEffect(() => {
    if (step !== "scanning" || !scanId) return;
    const interval = setInterval(async () => {
      try {
        const resp = await onboardApi.getScan(scanId);
        setScan(resp.data);
        if (resp.data.status === "completed") {
          setStep("results");
          const deps = resp.data.results ?? [];
          const sel: Record<number, boolean> = {};
          const assign: Record<number, { mode: "new" | "existing"; newName?: string }> = {};
          deps.forEach((d, i) => {
            sel[i] = true;
            assign[i] = { mode: "new", newName: d.name.replace(/\//g, "-") };
          });
          setSelections(sel);
          setProjectAssignments(assign);
          clearInterval(interval);
        } else if (resp.data.status === "failed") {
          setError(resp.data.error || "Scan failed");
          setStep("input");
          clearInterval(interval);
        }
      } catch {
        // Keep polling
      }
    }, 2000);
    return () => clearInterval(interval);
  }, [step, scanId]);

  // Elapsed time counter during scanning
  useEffect(() => {
    if (step !== "scanning") { setElapsed(0); return; }
    const start = Date.now();
    const timer = setInterval(() => setElapsed(Math.floor((Date.now() - start) / 1000)), 1000);
    return () => clearInterval(timer);
  }, [step]);

  // Auto-start scan from ?repo= query param
  useEffect(() => {
    const repo = searchParams.get("repo");
    if (repo && !autoStarted) {
      setAutoStarted(true);
      setRepoUrl(repo);
      beginScan(repo);
    }
  }, [searchParams, autoStarted]);

  const beginScan = async (url: string) => {
    setError(null);
    try {
      const resp = await onboardApi.scan(url);
      const scanData = resp.data;
      setScanId(scanData.id);
      setScan(scanData);
      // If scan is already completed (resuming a finished scan), go straight to results
      if (scanData.status === "completed") {
        const deps = scanData.results ?? [];
        const sel: Record<number, boolean> = {};
        const assign: Record<number, { mode: "new" | "existing"; newName?: string }> = {};
        deps.forEach((d, i) => {
          sel[i] = true;
          assign[i] = { mode: "new", newName: d.name.replace(/\//g, "-") };
        });
        setSelections(sel);
        setProjectAssignments(assign);
        setStep("results");
      } else if (scanData.status === "failed") {
        setError(scanData.error || "Scan failed");
        setStep("input");
      } else {
        setStep("scanning");
      }
    } catch (e: any) {
      setError(e.message || "Failed to start scan");
    }
  };

  const startScan = () => {
    if (repoUrl.trim()) beginScan(repoUrl);
  };

  const applySelections = async () => {
    if (!scan?.results || !scanId) return;
    setApplying(true);
    setError(null);

    const sels: OnboardSelection[] = [];
    scan.results.forEach((dep, i) => {
      if (!selections[i]) return;
      const assign = projectAssignments[i];
      sels.push({
        dep_name: dep.name,
        upstream_repo: dep.upstream_repo,
        provider: dep.provider,
        project_id: assign?.mode === "existing" ? assign.projectId : undefined,
        new_project_name: assign?.mode === "new" ? (assign.newName || dep.name.replace(/\//g, "-")) : undefined,
      });
    });

    try {
      const resp = await onboardApi.apply(scanId, sels);
      setApplyResult(resp.data);
      setStep("applied");
    } catch (e: any) {
      setError(e.message || "Failed to apply selections");
    } finally {
      setApplying(false);
    }
  };

  const deps = scan?.results ?? [];
  const selectedCount = Object.values(selections).filter(Boolean).length;

  return (
    <div className="flex flex-col gap-4 fade-in">
      {/* Header */}
      <div>
        <h1
          style={{
            fontFamily: "var(--font-fraunces)",
            fontSize: "24px",
            fontWeight: 700,
            color: "#111113",
          }}
        >
          Quick Onboard
        </h1>
        <p
          className="mt-1 text-[13px]"
          style={{ color: "#6b7280", fontFamily: "var(--font-dm-sans)" }}
        >
          Scan a GitHub repository to detect dependencies and start tracking their releases.
        </p>
      </div>

      {error && (
        <div
          className="rounded-md px-4 py-3 text-[13px]"
          style={{
            backgroundColor: "#fef2f2",
            border: "1px solid #fecaca",
            color: "#b91c1c",
            fontFamily: "var(--font-dm-sans)",
          }}
        >
          {error}
        </div>
      )}

      {/* Step 1: Input */}
      {step === "input" && (
        <div
          className="rounded-md px-6 py-8"
          style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
        >
          <div className="max-w-xl">
            <label
              className="block text-[13px] font-medium mb-2"
              style={{ color: "#374151", fontFamily: "var(--font-dm-sans)" }}
            >
              GitHub Repository URL
            </label>
            <div className="flex gap-2">
              <input
                type="text"
                value={repoUrl}
                onChange={(e) => setRepoUrl(e.target.value)}
                placeholder="owner/repo or https://github.com/owner/repo"
                className="flex-1 rounded-md border px-3 py-2 text-[13px] focus:outline-none focus:ring-2"
                style={{
                  borderColor: "#e8e8e5",
                  color: "#111113",
                  fontFamily: "'JetBrains Mono', monospace",
                  backgroundColor: "#ffffff",
                }}
                onFocus={(e) => { e.currentTarget.style.borderColor = "#e8601a"; }}
                onBlur={(e) => { e.currentTarget.style.borderColor = "#e8e8e5"; }}
                onKeyDown={(e) => e.key === "Enter" && repoUrl.trim() && startScan()}
              />
              <button
                onClick={startScan}
                disabled={!repoUrl.trim()}
                className="flex items-center gap-2 rounded-md px-4 py-2 text-[13px] font-medium text-white transition-opacity hover:opacity-90 disabled:opacity-40 disabled:cursor-not-allowed"
                style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
              >
                <Search className="h-4 w-4" />
                Scan
              </button>
            </div>
            <p className="mt-2 text-[12px]" style={{ color: "#9ca3af" }}>
              We&apos;ll scan for go.mod, package.json, requirements.txt, Cargo.toml, and other dependency files.
            </p>
          </div>
        </div>
      )}

      {/* Step 2: Scanning */}
      {step === "scanning" && (
        <div
          className="flex flex-col items-center justify-center rounded-md py-16"
          style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
        >
          <div
            className="flex items-center justify-center rounded-full mb-4"
            style={{ width: 48, height: 48, backgroundColor: "#fff7ed" }}
          >
            <Loader2 className="h-6 w-6 animate-spin" style={{ color: "#e8601a" }} />
          </div>
          <p
            className="text-[14px] font-medium"
            style={{ color: "#111113", fontFamily: "var(--font-dm-sans)" }}
          >
            {scan?.status === "processing"
              ? "Analyzing dependency files..."
              : "Waiting to start scan..."}
          </p>
          <div className="mt-3 flex flex-col items-center gap-2">
            {/* Progress steps */}
            <div className="flex items-center gap-6">
              <ScanStep
                label="Queued"
                done={scan?.status === "processing"}
                active={scan?.status === "pending"}
              />
              <StepConnector done={scan?.status === "processing"} />
              <ScanStep
                label="Fetching files"
                done={false}
                active={scan?.status === "processing"}
              />
              <StepConnector done={false} />
              <ScanStep
                label="Extracting deps"
                done={false}
                active={false}
              />
            </div>
            <p className="mt-2 text-[12px]" style={{ color: "#9ca3af" }}>
              {elapsed > 0 && `${elapsed}s elapsed · `}
              {scan?.repo_url && (
                <span style={{ fontFamily: "'JetBrains Mono', monospace" }}>{scan.repo_url}</span>
              )}
            </p>
          </div>
        </div>
      )}

      {/* Step 3: Results — empty */}
      {step === "results" && deps.length === 0 && (
        <div
          className="flex flex-col items-center justify-center rounded-md py-16"
          style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
        >
          <PackageSearch className="h-8 w-8 mb-3" style={{ color: "#c4c4c0" }} />
          <p
            className="text-[14px]"
            style={{ color: "#6b7280", fontFamily: "var(--font-dm-sans)" }}
          >
            No dependencies detected in this repository.
          </p>
          <button
            onClick={() => { setStep("input"); setRepoUrl(""); }}
            className="mt-4 text-[13px] font-medium hover:underline"
            style={{ color: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
          >
            Try another repository
          </button>
        </div>
      )}

      {/* Step 3: Results — with deps */}
      {step === "results" && deps.length > 0 && (
        <>
          <div className="flex items-center justify-between">
            <p className="text-[13px]" style={{ color: "#6b7280", fontFamily: "var(--font-dm-sans)" }}>
              Found <span style={{ color: "#111113", fontWeight: 600 }}>{deps.length}</span> dependencies.
              {" "}Selected: <span style={{ color: "#111113", fontWeight: 600 }}>{selectedCount}</span>
            </p>
            <button
              onClick={applySelections}
              disabled={selectedCount === 0 || applying}
              className="flex items-center gap-2 rounded-md px-4 py-2 text-[13px] font-medium text-white transition-opacity hover:opacity-90 disabled:opacity-40"
              style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
            >
              {applying ? <Loader2 className="h-4 w-4 animate-spin" /> : <PackageSearch className="h-4 w-4" />}
              Track Selected ({selectedCount})
            </button>
          </div>

          <div
            className="overflow-hidden rounded-md"
            style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
          >
            <table className="w-full text-[13px]" style={{ fontFamily: "var(--font-dm-sans)" }}>
              <thead>
                <tr style={{ borderBottom: "1px solid #e8e8e5", backgroundColor: "#fafaf9" }}>
                  <th className="w-10 px-3 py-2.5">
                    <input
                      type="checkbox"
                      checked={selectedCount === deps.length}
                      onChange={(e) => {
                        const val = e.target.checked;
                        const s: Record<number, boolean> = {};
                        deps.forEach((_, i) => { s[i] = val; });
                        setSelections(s);
                      }}
                      className="rounded"
                      style={{ accentColor: "#e8601a" }}
                    />
                  </th>
                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
                    Dependency
                  </th>
                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
                    Version
                  </th>
                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
                    Ecosystem
                  </th>
                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
                    Source
                  </th>
                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
                    Project
                  </th>
                </tr>
              </thead>
              <tbody>
                {deps.map((dep, i) => {
                  const eco = ecosystemColors[dep.ecosystem] || ecosystemColors.other;
                  return (
                    <tr
                      key={i}
                      className="transition-colors hover:bg-[#fafaf9]"
                      style={{
                        borderBottom: i < deps.length - 1 ? "1px solid #e8e8e5" : undefined,
                        opacity: selections[i] ? 1 : 0.5,
                      }}
                    >
                      <td className="px-3 py-2.5">
                        <input
                          type="checkbox"
                          checked={!!selections[i]}
                          onChange={(e) => setSelections({ ...selections, [i]: e.target.checked })}
                          className="rounded"
                          style={{ accentColor: "#e8601a" }}
                        />
                      </td>
                      <td className="px-3 py-2.5">
                        <span
                          className="text-[12px]"
                          style={{ fontFamily: "'JetBrains Mono', monospace", color: "#111113" }}
                        >
                          {dep.name}
                        </span>
                      </td>
                      <td className="px-3 py-2.5">
                        <span
                          className="inline-flex items-center rounded px-1.5 py-0.5 text-[11px]"
                          style={{
                            backgroundColor: "#f3f3f1",
                            fontFamily: "'JetBrains Mono', monospace",
                            color: "#374151",
                          }}
                        >
                          {dep.version}
                        </span>
                      </td>
                      <td className="px-3 py-2.5">
                        <span
                          className="inline-flex items-center rounded-full px-2 py-0.5 text-[11px] font-medium"
                          style={{
                            backgroundColor: eco.bg,
                            color: eco.text,
                            border: `1px solid ${eco.border}`,
                          }}
                        >
                          {dep.ecosystem}
                        </span>
                      </td>
                      <td className="px-3 py-2.5">
                        <span className="text-[12px]" style={{ color: "#6b7280", fontFamily: "'JetBrains Mono', monospace" }}>
                          {dep.upstream_repo}
                        </span>
                      </td>
                      <td className="px-3 py-2.5">
                        <select
                          value={projectAssignments[i]?.mode === "existing" ? projectAssignments[i]?.projectId : "__new__"}
                          onChange={(e) => {
                            const val = e.target.value;
                            if (val === "__new__") {
                              setProjectAssignments({
                                ...projectAssignments,
                                [i]: { mode: "new", newName: dep.name.replace(/\//g, "-") },
                              });
                            } else {
                              setProjectAssignments({
                                ...projectAssignments,
                                [i]: { mode: "existing", projectId: val },
                              });
                            }
                          }}
                          className="rounded-md border px-2 py-1 text-[12px] bg-white"
                          style={{
                            borderColor: "#e8e8e5",
                            color: "#374151",
                            fontFamily: "var(--font-dm-sans)",
                          }}
                        >
                          <option value="__new__">Create new project</option>
                          {existingProjects.map((p) => (
                            <option key={p.id} value={p.id}>{p.name}</option>
                          ))}
                        </select>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </>
      )}

      {/* Step 4: Applied */}
      {step === "applied" && applyResult && (
        <>
          <div
            className="rounded-md px-4 py-3 text-[13px]"
            style={{
              backgroundColor: "#f0fdf4",
              border: "1px solid #bbf7d0",
              color: "#15803d",
              fontFamily: "var(--font-dm-sans)",
            }}
          >
            <div className="flex items-center gap-2">
              <Check className="h-4 w-4" />
              Successfully created {applyResult.created_sources.length} source{applyResult.created_sources.length !== 1 ? "s" : ""}
              {applyResult.created_projects.length > 0 && ` and ${applyResult.created_projects.length} project${applyResult.created_projects.length !== 1 ? "s" : ""}`}.
            </div>
          </div>

          {applyResult.skipped.length > 0 && (
            <div
              className="rounded-md px-4 py-3 text-[13px]"
              style={{
                backgroundColor: "#fefce8",
                border: "1px solid #fde68a",
                color: "#a16207",
                fontFamily: "var(--font-dm-sans)",
              }}
            >
              <p className="font-medium mb-1">Skipped ({applyResult.skipped.length}):</p>
              <ul className="list-disc pl-5 text-[12px]">
                {applyResult.skipped.map((s, i) => <li key={i}>{s}</li>)}
              </ul>
            </div>
          )}

          <div className="flex gap-3">
            <button
              onClick={() => router.push("/projects")}
              className="flex items-center gap-2 rounded-md px-4 py-2 text-[13px] font-medium text-white transition-opacity hover:opacity-90"
              style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
            >
              View Projects
              <ArrowRight className="h-3.5 w-3.5" />
            </button>
            <button
              onClick={() => { setStep("input"); setRepoUrl(""); setScanId(null); setScan(null); setApplyResult(null); }}
              className="rounded-md border px-4 py-2 text-[13px] transition-colors hover:bg-[#f3f3f1]"
              style={{
                borderColor: "#e8e8e5",
                color: "#374151",
                fontFamily: "var(--font-dm-sans)",
              }}
            >
              Scan Another Repo
            </button>
          </div>
        </>
      )}
    </div>
  );
}

/* --- Progress step components --- */

function ScanStep({ label, done, active }: { label: string; done: boolean; active: boolean }) {
  return (
    <div className="flex items-center gap-1.5">
      <div
        className="flex items-center justify-center rounded-full"
        style={{
          width: 18,
          height: 18,
          backgroundColor: done ? "#f0fdf4" : active ? "#fff7ed" : "#f3f3f1",
          border: `1.5px solid ${done ? "#16a34a" : active ? "#e8601a" : "#e8e8e5"}`,
        }}
      >
        {done ? (
          <Check className="h-3 w-3" style={{ color: "#16a34a" }} />
        ) : active ? (
          <Loader2 className="h-3 w-3 animate-spin" style={{ color: "#e8601a" }} />
        ) : (
          <div className="h-1.5 w-1.5 rounded-full" style={{ backgroundColor: "#d1d5db" }} />
        )}
      </div>
      <span
        className="text-[12px]"
        style={{
          color: done ? "#16a34a" : active ? "#111113" : "#9ca3af",
          fontFamily: "var(--font-dm-sans)",
          fontWeight: active ? 500 : 400,
        }}
      >
        {label}
      </span>
    </div>
  );
}

function StepConnector({ done }: { done: boolean }) {
  return (
    <div
      className="h-px"
      style={{
        width: 24,
        backgroundColor: done ? "#16a34a" : "#e8e8e5",
      }}
    />
  );
}

"use client";

import React, { useState, useEffect, Suspense } from "react";
import useSWR from "swr";
import { useRouter, useSearchParams } from "next/navigation";
import { onboard as onboardApi, projects as projectsApi } from "@/lib/api/client";
import type { OnboardScan, OnboardSelection, Project } from "@/lib/api/types";
import { Loader2, Check, Search, PackageSearch, ArrowRight } from "lucide-react";

type Step = "input" | "scanning" | "results" | "applied";

const ecosystemColors: Record<string, { bg: string; text: string; border: string }> = {
  go: { bg: "#ecfeff", text: "#0e7490", border: "#a5f3fc" },
  npm: { bg: "#fef2f2", text: "#b91c1c", border: "#fecaca" },
  pypi: { bg: "#fefce8", text: "#a16207", border: "#fde68a" },
  cargo: { bg: "#fff7ed", text: "#c2410c", border: "#fed7aa" },
  rubygems: { bg: "#fdf2f8", text: "#be185d", border: "#fbcfe8" },
  maven: { bg: "#eff6ff", text: "#1d4ed8", border: "#bfdbfe" },
  gradle: { bg: "#eff6ff", text: "#1d4ed8", border: "#bfdbfe" },
  docker: { bg: "#eff6ff", text: "#1d4ed8", border: "#bfdbfe" },
  other: { bg: "#f3f3f1", text: "#6b7280", border: "#e8e8e5" },
};

export default function OnboardPage() {
  return (
    <Suspense>
      <OnboardPageInner />
    </Suspense>
  );
}

function OnboardPageInner() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const [step, setStep] = useState<Step>("input");
  const [repoUrl, setRepoUrl] = useState("");
  const [scanId, setScanId] = useState<string | null>(null);
  const [scan, setScan] = useState<OnboardScan | null>(null);
  const [selections, setSelections] = useState<Record<number, boolean>>({});
  const [projectAssignments, setProjectAssignments] = useState<Record<number, { mode: "new" | "existing"; projectId?: string; newName?: string }>>({});
  const [applying, setApplying] = useState(false);
  const [applyResult, setApplyResult] = useState<{ created_projects: Project[]; created_sources: Source[]; skipped: string[] } | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [autoStarted, setAutoStarted] = useState(false);
  const [elapsed, setElapsed] = useState(0);

  // Fetch existing projects for the dropdown
  const { data: projectsResp } = useSWR("projects-all", () => projectsApi.list(1, 200));
  const existingProjects = projectsResp?.data ?? [];

  // Poll scan status
  useEffect(() => {
    if (step !== "scanning" || !scanId) return;
    const interval = setInterval(async () => {
      try {
        const resp = await onboardApi.getScan(scanId);
        setScan(resp.data);
        if (resp.data.status === "completed") {
          setStep("results");
          const deps = resp.data.results ?? [];
          const sel: Record<number, boolean> = {};
          const assign: Record<number, { mode: "new" | "existing"; newName?: string }> = {};
          deps.forEach((d, i) => {
            sel[i] = true;
            assign[i] = { mode: "new", newName: d.name.replace(/\//g, "-") };
          });
          setSelections(sel);
          setProjectAssignments(assign);
          clearInterval(interval);
        } else if (resp.data.status === "failed") {
          setError(resp.data.error || "Scan failed");
          setStep("input");
          clearInterval(interval);
        }
      } catch {
        // Keep polling
      }
    }, 2000);
    return () => clearInterval(interval);
  }, [step, scanId]);

  // Elapsed time counter during scanning
  useEffect(() => {
    if (step !== "scanning") { setElapsed(0); return; }
    const start = Date.now();
    const timer = setInterval(() => setElapsed(Math.floor((Date.now() - start) / 1000)), 1000);
    return () => clearInterval(timer);
  }, [step]);

  // Auto-start scan from ?repo= query param
  useEffect(() => {
    const repo = searchParams.get("repo");
    if (repo && !autoStarted) {
      setAutoStarted(true);
      setRepoUrl(repo);
      beginScan(repo);
    }
  }, [searchParams, autoStarted]);

  const beginScan = async (url: string) => {
    setError(null);
    try {
      const resp = await onboardApi.scan(url);
      const scanData = resp.data;
      setScanId(scanData.id);
      setScan(scanData);
      // If scan is already completed (resuming a finished scan), go straight to results
      if (scanData.status === "completed") {
        const deps = scanData.results ?? [];
        const sel: Record<number, boolean> = {};
        const assign: Record<number, { mode: "new" | "existing"; newName?: string }> = {};
        deps.forEach((d, i) => {
          sel[i] = true;
          assign[i] = { mode: "new", newName: d.name.replace(/\//g, "-") };
        });
        setSelections(sel);
        setProjectAssignments(assign);
        setStep("results");
      } else if (scanData.status === "failed") {
        setError(scanData.error || "Scan failed");
        setStep("input");
      } else {
        setStep("scanning");
      }
    } catch (e: any) {
      setError(e.message || "Failed to start scan");
    }
  };

  const startScan = () => {
    if (repoUrl.trim()) beginScan(repoUrl);
  };

  const applySelections = async () => {
    if (!scan?.results || !scanId) return;
    setApplying(true);
    setError(null);

    const sels: OnboardSelection[] = [];
    scan.results.forEach((dep, i) => {
      if (!selections[i]) return;
      const assign = projectAssignments[i];
      sels.push({
        dep_name: dep.name,
        upstream_repo: dep.upstream_repo,
        provider: dep.provider,
        project_id: assign?.mode === "existing" ? assign.projectId : undefined,
        new_project_name: assign?.mode === "new" ? (assign.newName || dep.name.replace(/\//g, "-")) : undefined,
      });
    });

    try {
      const resp = await onboardApi.apply(scanId, sels);
      setApplyResult(resp.data);
      setStep("applied");
    } catch (e: any) {
      setError(e.message || "Failed to apply selections");
    } finally {
      setApplying(false);
    }
  };

  const deps = scan?.results ?? [];
  const selectedCount = Object.values(selections).filter(Boolean).length;

  return (
    <div className="flex flex-col gap-4 fade-in">
      {/* Header */}
      <div>
        <h1
          style={{
            fontFamily: "var(--font-fraunces)",
            fontSize: "24px",
            fontWeight: 700,
            color: "#111113",
          }}
        >
          Quick Onboard
        </h1>
        <p
          className="mt-1 text-[13px]"
          style={{ color: "#6b7280", fontFamily: "var(--font-dm-sans)" }}
        >
          Scan a GitHub repository to detect dependencies and start tracking their releases.
        </p>
      </div>

      {error && (
        <div
          className="rounded-md px-4 py-3 text-[13px]"
          style={{
            backgroundColor: "#fef2f2",
            border: "1px solid #fecaca",
            color: "#b91c1c",
            fontFamily: "var(--font-dm-sans)",
          }}
        >
          {error}
        </div>
      )}

      {/* Step 1: Input */}
      {step === "input" && (
        <div
          className="rounded-md px-6 py-8"
          style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
        >
          <div className="max-w-xl">
            <label
              className="block text-[13px] font-medium mb-2"
              style={{ color: "#374151", fontFamily: "var(--font-dm-sans)" }}
            >
              GitHub Repository URL
            </label>
            <div className="flex gap-2">
              <input
                type="text"
                value={repoUrl}
                onChange={(e) => setRepoUrl(e.target.value)}
                placeholder="owner/repo or https://github.com/owner/repo"
                className="flex-1 rounded-md border px-3 py-2 text-[13px] focus:outline-none focus:ring-2"
                style={{
                  borderColor: "#e8e8e5",
                  color: "#111113",
                  fontFamily: "'JetBrains Mono', monospace",
                  backgroundColor: "#ffffff",
                }}
                onFocus={(e) => { e.currentTarget.style.borderColor = "#e8601a"; }}
                onBlur={(e) => { e.currentTarget.style.borderColor = "#e8e8e5"; }}
                onKeyDown={(e) => e.key === "Enter" && repoUrl.trim() && startScan()}
              />
              <button
                onClick={startScan}
                disabled={!repoUrl.trim()}
                className="flex items-center gap-2 rounded-md px-4 py-2 text-[13px] font-medium text-white transition-opacity hover:opacity-90 disabled:opacity-40 disabled:cursor-not-allowed"
                style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
              >
                <Search className="h-4 w-4" />
                Scan
              </button>
            </div>
            <p className="mt-2 text-[12px]" style={{ color: "#9ca3af" }}>
              We&apos;ll scan for go.mod, package.json, requirements.txt, Cargo.toml, and other dependency files.
            </p>
          </div>
        </div>
      )}

      {/* Step 2: Scanning */}
      {step === "scanning" && (
        <div
          className="flex flex-col items-center justify-center rounded-md py-16"
          style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
        >
          <div
            className="flex items-center justify-center rounded-full mb-4"
            style={{ width: 48, height: 48, backgroundColor: "#fff7ed" }}
          >
            <Loader2 className="h-6 w-6 animate-spin" style={{ color: "#e8601a" }} />
          </div>
          <p
            className="text-[14px] font-medium"
            style={{ color: "#111113", fontFamily: "var(--font-dm-sans)" }}
          >
            {scan?.status === "processing"
              ? "Analyzing dependency files..."
              : "Waiting to start scan..."}
          </p>
          <div className="mt-3 flex flex-col items-center gap-2">
            {/* Progress steps */}
            <div className="flex items-center gap-6">
              <ScanStep
                label="Queued"
                done={scan?.status === "processing"}
                active={scan?.status === "pending"}
              />
              <StepConnector done={scan?.status === "processing"} />
              <ScanStep
                label="Fetching files"
                done={false}
                active={scan?.status === "processing"}
              />
              <StepConnector done={false} />
              <ScanStep
                label="Extracting deps"
                done={false}
                active={false}
              />
            </div>
            <p className="mt-2 text-[12px]" style={{ color: "#9ca3af" }}>
              {elapsed > 0 && `${elapsed}s elapsed · `}
              {scan?.repo_url && (
                <span style={{ fontFamily: "'JetBrains Mono', monospace" }}>{scan.repo_url}</span>
              )}
            </p>
          </div>
        </div>
      )}

      {/* Step 3: Results — empty */}
      {step === "results" && deps.length === 0 && (
        <div
          className="flex flex-col items-center justify-center rounded-md py-16"
          style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
        >
          <PackageSearch className="h-8 w-8 mb-3" style={{ color: "#c4c4c0" }} />
          <p
            className="text-[14px]"
            style={{ color: "#6b7280", fontFamily: "var(--font-dm-sans)" }}
          >
            No dependencies detected in this repository.
          </p>
          <button
            onClick={() => { setStep("input"); setRepoUrl(""); }}
            className="mt-4 text-[13px] font-medium hover:underline"
            style={{ color: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
          >
            Try another repository
          </button>
        </div>
      )}

      {/* Step 3: Results — with deps */}
      {step === "results" && deps.length > 0 && (
        <>
          <div className="flex items-center justify-between">
            <p className="text-[13px]" style={{ color: "#6b7280", fontFamily: "var(--font-dm-sans)" }}>
              Found <span style={{ color: "#111113", fontWeight: 600 }}>{deps.length}</span> dependencies.
              {" "}Selected: <span style={{ color: "#111113", fontWeight: 600 }}>{selectedCount}</span>
            </p>
            <button
              onClick={applySelections}
              disabled={selectedCount === 0 || applying}
              className="flex items-center gap-2 rounded-md px-4 py-2 text-[13px] font-medium text-white transition-opacity hover:opacity-90 disabled:opacity-40"
              style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
            >
              {applying ? <Loader2 className="h-4 w-4 animate-spin" /> : <PackageSearch className="h-4 w-4" />}
              Track Selected ({selectedCount})
            </button>
          </div>

          <div
            className="overflow-hidden rounded-md"
            style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
          >
            <table className="w-full text-[13px]" style={{ fontFamily: "var(--font-dm-sans)" }}>
              <thead>
                <tr style={{ borderBottom: "1px solid #e8e8e5", backgroundColor: "#fafaf9" }}>
                  <th className="w-10 px-3 py-2.5">
                    <input
                      type="checkbox"
                      checked={selectedCount === deps.length}
                      onChange={(e) => {
                        const val = e.target.checked;
                        const s: Record<number, boolean> = {};
                        deps.forEach((_, i) => { s[i] = val; });
                        setSelections(s);
                      }}
                      className="rounded"
                      style={{ accentColor: "#e8601a" }}
                    />
                  </th>
                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
                    Dependency
                  </th>
                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
                    Version
                  </th>
                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
                    Ecosystem
                  </th>
                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
                    Source
                  </th>
                  <th className="px-3 py-2.5 text-left text-[11px] font-semibold uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>
                    Project
                  </th>
                </tr>
              </thead>
              <tbody>
                {deps.map((dep, i) => {
                  const eco = ecosystemColors[dep.ecosystem] || ecosystemColors.other;
                  return (
                    <tr
                      key={i}
                      className="transition-colors hover:bg-[#fafaf9]"
                      style={{
                        borderBottom: i < deps.length - 1 ? "1px solid #e8e8e5" : undefined,
                        opacity: selections[i] ? 1 : 0.5,
                      }}
                    >
                      <td className="px-3 py-2.5">
                        <input
                          type="checkbox"
                          checked={!!selections[i]}
                          onChange={(e) => setSelections({ ...selections, [i]: e.target.checked })}
                          className="rounded"
                          style={{ accentColor: "#e8601a" }}
                        />
                      </td>
                      <td className="px-3 py-2.5">
                        <span
                          className="text-[12px]"
                          style={{ fontFamily: "'JetBrains Mono', monospace", color: "#111113" }}
                        >
                          {dep.name}
                        </span>
                      </td>
                      <td className="px-3 py-2.5">
                        <span
                          className="inline-flex items-center rounded px-1.5 py-0.5 text-[11px]"
                          style={{
                            backgroundColor: "#f3f3f1",
                            fontFamily: "'JetBrains Mono', monospace",
                            color: "#374151",
                          }}
                        >
                          {dep.version}
                        </span>
                      </td>
                      <td className="px-3 py-2.5">
                        <span
                          className="inline-flex items-center rounded-full px-2 py-0.5 text-[11px] font-medium"
                          style={{
                            backgroundColor: eco.bg,
                            color: eco.text,
                            border: `1px solid ${eco.border}`,
                          }}
                        >
                          {dep.ecosystem}
                        </span>
                      </td>
                      <td className="px-3 py-2.5">
                        <span className="text-[12px]" style={{ color: "#6b7280", fontFamily: "'JetBrains Mono', monospace" }}>
                          {dep.upstream_repo}
                        </span>
                      </td>
                      <td className="px-3 py-2.5">
                        <select
                          value={projectAssignments[i]?.mode === "existing" ? projectAssignments[i]?.projectId : "__new__"}
                          onChange={(e) => {
                            const val = e.target.value;
                            if (val === "__new__") {
                              setProjectAssignments({
                                ...projectAssignments,
                                [i]: { mode: "new", newName: dep.name.replace(/\//g, "-") },
                              });
                            } else {
                              setProjectAssignments({
                                ...projectAssignments,
                                [i]: { mode: "existing", projectId: val },
                              });
                            }
                          }}
                          className="rounded-md border px-2 py-1 text-[12px] bg-white"
                          style={{
                            borderColor: "#e8e8e5",
                            color: "#374151",
                            fontFamily: "var(--font-dm-sans)",
                          }}
                        >
                          <option value="__new__">Create new project</option>
                          {existingProjects.map((p) => (
                            <option key={p.id} value={p.id}>{p.name}</option>
                          ))}
                        </select>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </>
      )}

      {/* Step 4: Applied */}
      {step === "applied" && applyResult && (
        <>
          <div
            className="rounded-md px-4 py-3 text-[13px]"
            style={{
              backgroundColor: "#f0fdf4",
              border: "1px solid #bbf7d0",
              color: "#15803d",
              fontFamily: "var(--font-dm-sans)",
            }}
          >
            <div className="flex items-center gap-2">
              <Check className="h-4 w-4" />
              Successfully created {applyResult.created_sources.length} source{applyResult.created_sources.length !== 1 ? "s" : ""}
              {applyResult.created_projects.length > 0 && ` and ${applyResult.created_projects.length} project${applyResult.created_projects.length !== 1 ? "s" : ""}`}.
            </div>
          </div>

          {applyResult.skipped.length > 0 && (
            <div
              className="rounded-md px-4 py-3 text-[13px]"
              style={{
                backgroundColor: "#fefce8",
                border: "1px solid #fde68a",
                color: "#a16207",
                fontFamily: "var(--font-dm-sans)",
              }}
            >
              <p className="font-medium mb-1">Skipped ({applyResult.skipped.length}):</p>
              <ul className="list-disc pl-5 text-[12px]">
                {applyResult.skipped.map((s, i) => <li key={i}>{s}</li>)}
              </ul>
            </div>
          )}

          <div className="flex gap-3">
            <button
              onClick={() => router.push("/projects")}
              className="flex items-center gap-2 rounded-md px-4 py-2 text-[13px] font-medium text-white transition-opacity hover:opacity-90"
              style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
            >
              View Projects
              <ArrowRight className="h-3.5 w-3.5" />
            </button>
            <button
              onClick={() => { setStep("input"); setRepoUrl(""); setScanId(null); setScan(null); setApplyResult(null); }}
              className="rounded-md border px-4 py-2 text-[13px] transition-colors hover:bg-[#f3f3f1]"
              style={{
                borderColor: "#e8e8e5",
                color: "#374151",
                fontFamily: "var(--font-dm-sans)",
              }}
            >
              Scan Another Repo
            </button>
          </div>
        </>
      )}
    </div>
  );
}

/* --- Progress step components --- */

